firmware_template.source:
#include "battery_mon.h"
#include <Arduino.h>
#define BATT_PIN 35
#define DIVIDER_RATIO 2.0
static float _v=0;static int _pct=0;
static unsigned long _last=0;
void battery_setup(){analogReadResolution(12);analogSetAttenuation(ADC_11db);Serial.println("[batt] OK");}
void battery_loop(){
  if(millis()-_last<5000)return;_last=millis();
  int raw=0;for(int i=0;i<10;i++)raw+=analogRead(BATT_PIN);raw/=10;
  _v=(raw/4095.0)*3.3*DIVIDER_RATIO;
  _pct=constrain(map((int)(_v*100),320,420,0,100),0,100);
  Serial.printf("[batt] %.2fV %d%%\n",_v,_pct);
}
float battery_get_voltage(){return _v;}
int battery_get_percent(){return _pct;}
bool battery_is_low(){return _pct<20;}
